import React from "react";
import Header from "../../components/header/Header";
import Footer from "../../components/footer/Footer";
import ExperienceAccordion from "../../containers/experienceAccordion/ExperienceAccordion.js";
import "./Experience.css";
import { experience } from "../../portfolio.js";
import { Fade } from "react-reveal";
import ExperienceImg from "./ExperienceImg";

// Section accent colors — kept in sync with ExperienceAccordion
const SECTION_CHIP_COLORS = {
  Work: "#2962FF",
  Internships: "#FF8F00",
  Volunteerships: "#00C853",
};

function Experience(props) {
  const theme = props.theme;

  // Current role — first "Present" entry in the Work section
  const workSection = (experience.sections || []).find(
    (s) => s.title === "Work"
  );
  const currentRole = workSection?.experiences?.find((e) =>
    /present/i.test(e.duration || "")
  );

  return (
    <div className="experience-main">
      <Header theme={theme} setTheme={props.setTheme} />
      <div className="basic-experience">
        <Fade bottom duration={2000} distance="40px">
          <div className="experience-heading-div">
            <div className="experience-heading-img-div">
              <ExperienceImg theme={theme} />
            </div>
            <div className="experience-heading-text-div">
              <h1
                className="experience-heading-text"
                style={{ color: theme.text }}
              >
                {experience.title}
              </h1>
              <h3
                className="experience-heading-sub-text"
                style={{ color: theme.text }}
              >
                {experience["subtitle"]}
              </h3>
              <p
                className="experience-header-detail-text subTitle"
                style={{ color: theme.secondaryText }}
              >
                {experience["description"]}
              </p>

              {currentRole && (
                <div className="exp-current-pill" style={{ color: theme.text }}>
                  <span className="exp-current-pulse" aria-hidden="true" />
                  Currently — {currentRole.title} · {currentRole.company}
                </div>
              )}

              <div className="exp-hero-chips">
                {(experience.sections || []).map((s) => {
                  const c = SECTION_CHIP_COLORS[s.title] || "#2962FF";
                  return (
                    <span
                      className="exp-hero-chip"
                      key={s.title}
                      style={{ borderColor: `${c}66`, color: c }}
                    >
                      {s.experiences.length}{" "}
                      {s.title === "Work" ? "Work roles" : s.title}
                    </span>
                  );
                })}
              </div>
            </div>
          </div>
        </Fade>
      </div>
      <ExperienceAccordion sections={experience["sections"]} theme={theme} />
      <Footer theme={props.theme} onToggle={props.onToggle} />
    </div>
  );
}

export default Experience;
